package be.schaubroeck.lpb.rkm.rekenmotor.bv;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.WerkbonusLuik;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.CheckRegime;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementChecker;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.verdeler.BedragVerdelerFactory;
import be.schaubroeck.lpb.tools.FiscaleConstant;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.GewWrkwBv;
import com.google.common.collect.ImmutableSet;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Value;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Collection;
import java.util.Comparator;
import java.util.Set;
import java.util.SortedSet;
import java.util.TreeSet;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SCHOOLVERLATER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.WERKBONUS_HEEL_LAGE_LONEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.WERKBONUS_LAGE_LONEN_KEY;

@Slf4j
@Builder
@AllArgsConstructor
public class BerekenVerminderingBvWerkbonus {

    private static final LocalDate GRENS_VERMINDERNG_BV_WERKBONONUS_ZONDER_HERSRTRUCT = new LocalDate(2015, 9, 1);
    private static final LocalDate GRENS_VERMINDERNG_BV_WERKBONONUS_LIMIET = new LocalDate(2023, 1, 1);

    private static final Set<GewWrkwBv> FISCALE_WERKWIJZEN = ImmutableSet.of(GewWrkwBv.BAREMA_GN_KUMUL, GewWrkwBv.BAREMA_KUMUL, GewWrkwBv.BAREMA_INV_PVH);

    private final FiscaleConstant fiscaleConstanten;
    private final BvVoluntariaat bvVoluntariaat;
    private final LocalDate taxdatum;

    public void bereken(RekenContext mainContext, RekenTijd rekenTijd) {
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        if (heeftWerkbonus(mainContext, rekenTijd)) {
            if (heeftGrensBedragFiscaalJaar(persoon, rekenTijd)) {
                bepaalVerminderingBvWerkBonusTenOpzichteFiscaleGrens(mainContext, persoon);
            } else {
                bepaalVerminderingBvWerkBonusZonderFiscaleGrens(mainContext, persoon, rekenTijd);
            }
        }
    }

    private Money bepaalVoluntariaat(RekenContext mainContext, Persoon persoon) {
        Money voluntariaat = Money.ZERO;
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY)) {
                Collection<LoonElement> opdrachtElementen = manager.getOpdrachtsElementen(opdracht);
                voluntariaat = voluntariaat.add(bepaalVoluntariaat(opdrachtContext, opdrachtElementen));
            }
        }
        return voluntariaat;
    }

    private Money bepaalVoluntariaat(RekenContext opdrachtContext, Collection<LoonElement> opdrachtElementen) {
        return bvVoluntariaat.bepaalGewoon(opdrachtContext, opdrachtElementen);
    }

    private void bepaalVerminderingBvWerkBonusZonderFiscaleGrens(RekenContext mainContext, Persoon persoon, RekenTijd rekenTijd) {
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            if (FISCALE_WERKWIJZEN.contains(getWerkwijzeGewoneBezoldiging(opdracht))) {
                RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
                VerminderinBvWerkbonus verminderingBvWerkbonus = bepaalVerminderingBvWerkBonusOud(opdrachtContext, opdracht, rekenTijd);
                herverdeelBedrijfsvoorheffingOud(opdrachtContext, opdracht, verminderingBvWerkbonus);
            }
        }
    }

    public GewWrkwBv getWerkwijzeGewoneBezoldiging(Opdracht opdracht) {
        Opper laatsteGegevens = RekenTools.getOpperLaatsteGegevens(opdracht);
        return laatsteGegevens.getOpdrachtFiscaliteit().getWerkwijzeGewoneBezoldiging();
    }

    private boolean heeftGrensBedragFiscaalJaar(Persoon persoon, RekenTijd rekenTijd) {
        return rekenTijd.eindDatum.isAfter(GRENS_VERMINDERNG_BV_WERKBONONUS_LIMIET) && RekenTools.heeftOpdrachtContractueel(persoon);
    }

    @Value
    @AllArgsConstructor
    private static class VerminderinBvWerkbonus {
        Money luikA;
        Money luikB;

        Money get(WerkbonusLuik luik) {
            if (luik == WerkbonusLuik.LUIK_A) {
                return luikA;
            } else {
                return luikB;
            }
        }
    }

    private VerminderinBvWerkbonus bepaalVerminderingBvWerkBonusOud(RekenContext context, Opdracht opdracht, RekenTijd rekenTijd) {
        Money werkbonus = context.getMoney(WERKBONUS_LAGE_LONEN_KEY);
        if (rekenTijd.eindDatum.isBefore(GRENS_VERMINDERNG_BV_WERKBONONUS_ZONDER_HERSRTRUCT)) {
            werkbonus = werkbonus.add(context.getMoney(VERMINDERING_HERSTRUCTERING_KEY));
        }
        BigDecimal verminderingBvPercentageLuikA = fiscaleConstanten.getPercentageVerminderingBedrijfsvoorheffingWerkbonus();
        Money verminderingBvWerkbonus = werkbonus.multiply(verminderingBvPercentageLuikA.movePointLeft(2)).round(2);
        log.debug("verminderingBvWerkbonus Luik A:{};verminderingBvWerkbonusPercentage Luik A:{}", verminderingBvWerkbonus, verminderingBvPercentageLuikA);
        context.put(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY, verminderingBvWerkbonus);

        Money werkbonusB = context.getMoney(WERKBONUS_HEEL_LAGE_LONEN_KEY);
        BigDecimal verminderingBvPercentageLuikB = fiscaleConstanten.getPercentageVerminderingBedrijfsvoorheffingWerkbonusB();
        Money verminderingBvWerkbonusB = werkbonusB.multiply(verminderingBvPercentageLuikB.movePointLeft(2)).round(2);
        log.debug("verminderingBvWerkbonus Luik B:{};verminderingBvWerkbonusPercentage Luik B:{}", verminderingBvWerkbonusB, verminderingBvPercentageLuikB);
        context.put(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY, verminderingBvWerkbonusB);

        Money bedrijfsvoorheffing = bepaalBedrijfsvoorheffing(context, opdracht);

        return limiteerTotBedrijfsvoorheffing(context, bedrijfsvoorheffing, new VerminderinBvWerkbonus(verminderingBvWerkbonus, verminderingBvWerkbonusB));
    }

    private void bepaalVerminderingBvWerkBonusTenOpzichteFiscaleGrens(RekenContext mainContext, Persoon persoon) {
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        Money verminderingBvFiscaalJaarOtherLuikA = persoonsDataManager.getVerminderingBvWerkbonusFiscaalJaarOtherMonths(WerkbonusLuik.LUIK_A);
        Money verminderingBvFiscaalJaarOtherLuikB = persoonsDataManager.getVerminderingBvWerkbonusFiscaalJaarOtherMonths(WerkbonusLuik.LUIK_B);

        Money verminderingBvFiscaalJaarLuikA = bepaalVerminderingBvOverFiscaalJaar(mainContext, WerkbonusLuik.LUIK_A);
        Money verminderingBvFiscaalJaarLuikB = bepaalVerminderingBvOverFiscaalJaar(mainContext, WerkbonusLuik.LUIK_B);

        Money grensBedrag = fiscaleConstanten.getGrensBedragFiscaleWerkbonus();
        Money limietVerminBvFiscaalJaar = grensBedrag.min(verminderingBvFiscaalJaarLuikA);
        Money verminderingBvWerkbonusA = limietVerminBvFiscaalJaar.subtract(verminderingBvFiscaalJaarOtherLuikA).max(Money.ZERO);
        mainContext.put(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY, verminderingBvWerkbonusA);

        Money grensBedrag2 = grensBedrag.subtract(verminderingBvFiscaalJaarLuikA).max(Money.ZERO);
        Money limietVerminBvFiscaalJaar2 = grensBedrag2.min(verminderingBvFiscaalJaarLuikB);
        Money verminderingBvWerkbonusB = limietVerminBvFiscaalJaar2.subtract(verminderingBvFiscaalJaarOtherLuikB).max(Money.ZERO);
        mainContext.put(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY, verminderingBvWerkbonusB);

        log.debug("verminderingBvWerkbonus Luik A:{}; totaal fiscaal jaar: {}", verminderingBvWerkbonusA, verminderingBvFiscaalJaarLuikA);
        log.debug("verminderingBvWerkbonus Luik B:{}; totaal fiscaal jaar: {}", verminderingBvWerkbonusB, verminderingBvFiscaalJaarLuikB);

        Money bedrijfsvoorheffing = bepaalBedrijfsvoorheffing(mainContext, persoon);
        VerminderinBvWerkbonus verminderingBvWerkbonus = new VerminderinBvWerkbonus(verminderingBvWerkbonusA, verminderingBvWerkbonusB);
        verminderingBvWerkbonus = limiteerTotBedrijfsvoorheffing(mainContext, bedrijfsvoorheffing, verminderingBvWerkbonus);
        herverdeelBedrijfsvoorheffing(mainContext, persoon, verminderingBvWerkbonus);
    }

    private VerminderinBvWerkbonus limiteerTotBedrijfsvoorheffing(RekenContext context, Money bedrijfsvoorheffing, VerminderinBvWerkbonus verminderinBvWerkbonus) {
        Money verminderingBvWerkbonusTotaal = verminderinBvWerkbonus.getLuikA().add(verminderinBvWerkbonus.luikB);
        Money verminderingBvWerkbonusTotaalLimiet = verminderingBvWerkbonusTotaal.min(bedrijfsvoorheffing).max(Money.ZERO);
        Money verminderingBvWerkbonusALimiet = verminderinBvWerkbonus.getLuikA().min(verminderingBvWerkbonusTotaalLimiet);
        Money verminderingBvWerkbonusBLimiet = verminderingBvWerkbonusTotaalLimiet.subtract(verminderingBvWerkbonusALimiet).max(Money.ZERO);

        log.debug("verminderingBvWerkbonus Luik A begrenst op bv:{}", verminderingBvWerkbonusALimiet);
        log.debug("verminderingBvWerkbonus Luik B begrenst op bv:{}", verminderingBvWerkbonusBLimiet);

        context.put(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY, verminderingBvWerkbonusALimiet);
        context.put(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY, verminderingBvWerkbonusBLimiet);
        return new VerminderinBvWerkbonus(verminderingBvWerkbonusALimiet, verminderingBvWerkbonusBLimiet);
    }

    private Money bepaalVerminderingBvOverFiscaalJaar(RekenContext context, WerkbonusLuik luik) {
        PersoonsDataManager persoonsDataManager = context.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        Money werkbonus = bepaalWerkbonusPersoon(context, luik);
        Money werkbonusTotaalFiscaalJaarOtherMonths = persoonsDataManager.getWerkbonusFiscaalJaarOtherMonths(luik);
        Money werkBonusTotaal = werkbonusTotaalFiscaalJaarOtherMonths.add(werkbonus);
        BigDecimal percentageVermindering = getPercentageVermindering(luik);
        log.debug("luik: {}werkbonus:{}; werkbonusTotaalFiscaalJaarOtherMonths: {}; percentageVermindering:{}", luik, werkbonus, werkbonusTotaalFiscaalJaarOtherMonths,
                percentageVermindering);
        return werkBonusTotaal.multiply(percentageVermindering).round(2);
    }

    private Money bepaalWerkbonusPersoon(RekenContext context, WerkbonusLuik luik) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> persoonsElementen = manager.getPersoonsElementen();
        return persoonsElementen.stream().map(x -> x.getPropertyMoney(luik.getBedragKey())).reduce(Money.ZERO, Money::add);
    }

    private Money bepaalWerkbonusOpdrachtenBarema(RekenContext context, Persoon persoon, WerkbonusLuik luik) {
        Money totaal = Money.ZERO;
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            if (FISCALE_WERKWIJZEN.contains(getWerkwijzeGewoneBezoldiging(opdracht))) {
                totaal = totaal.add(bepaalWerkbonus(context, opdracht, luik));
            }
        }
        return totaal;
    }

    private Money bepaalWerkbonus(RekenContext context, Opdracht opdracht, WerkbonusLuik luik) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> elementen = manager.getOpdrachtsElementen(opdracht);
        return elementen.stream().map(x -> x.getPropertyMoney(luik.getBedragKey())).reduce(Money.ZERO, Money::add);
    }

    private Money bepaalBedrijfsvoorheffing(RekenContext context, Opdracht opdracht) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Money bedrijfsvoorheffing = RekenTools.getSomProperty(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, manager.getOpdrachtsElementen(opdracht));
        Money voluntariaat = bepaalVoluntariaat(context, manager.getOpdrachtsElementen(opdracht));
        return bedrijfsvoorheffing.subtract(voluntariaat);
    }

    private Money bepaalBedrijfsvoorheffing(RekenContext context, Persoon persoon) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Money bedrijfsvoorheffing = RekenTools.getSomProperty(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, manager.getPersoonsElementen());
        Money voluntariaat = bepaalVoluntariaat(context, persoon);
        return bedrijfsvoorheffing.subtract(voluntariaat);
    }

    private BigDecimal getPercentageVermindering(WerkbonusLuik luik) {
        if (luik == WerkbonusLuik.LUIK_A) {
            return fiscaleConstanten.getPercentageVerminderingBedrijfsvoorheffingWerkbonus().movePointLeft(2);
        } else {
            return fiscaleConstanten.getPercentageVerminderingBedrijfsvoorheffingWerkbonusB().movePointLeft(2);
        }
    }

    protected void herverdeelBedrijfsvoorheffing(
            RekenContext context, Persoon persoon, VerminderinBvWerkbonus verminderingBvWerkbonus) {
        SortedSet<Opdracht> opdrachten = new TreeSet<>(Comparator.comparing(Opdracht::getOpdrachtnr));
        opdrachten.addAll(persoon.getOpdrachten());
        Money carryoverA = Money.ZERO;
        Money carryoverB = Money.ZERO;
        Money werkbonusTotaalA = bepaalWerkbonusOpdrachtenBarema(context, persoon, WerkbonusLuik.LUIK_A);
        Money werkbonusTotaalB = bepaalWerkbonusOpdrachtenBarema(context, persoon, WerkbonusLuik.LUIK_B);
        for (Opdracht opdracht : opdrachten) {
            if (FISCALE_WERKWIJZEN.contains(getWerkwijzeGewoneBezoldiging(opdracht))) {
                carryoverA = herverdeelBedrijfsvoorheffing(context, opdracht, verminderingBvWerkbonus, WerkbonusLuik.LUIK_A, werkbonusTotaalA, carryoverA);
                carryoverB = herverdeelBedrijfsvoorheffing(context, opdracht, verminderingBvWerkbonus, WerkbonusLuik.LUIK_B, werkbonusTotaalB, carryoverB);
            }
        }
    }

    protected Money herverdeelBedrijfsvoorheffing(
            RekenContext context, Opdracht opdracht, VerminderinBvWerkbonus verminderingBvWerkbonus, WerkbonusLuik luik, Money werkbonusTotaal, Money carryover) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);

        Money carryoverOut = Money.ZERO;
        if (werkbonusTotaal.signum() != 0) {
            Money werkbonus = bepaalWerkbonus(context, opdracht, luik);
            Money verminderingBvWerkbonusA = verminderingBvWerkbonus.get(luik).multiply(werkbonus.divide(werkbonusTotaal)).add(carryover);
            carryoverOut = verminderingBvWerkbonusA.subtract(verminderingBvWerkbonusA.round(2));
            verminderingBvWerkbonusA = verminderingBvWerkbonusA.round(2);

            Collection<LoonElement> opdrachtElementen = manager.getOpdrachtsElementen(opdracht);
            Money bbOpdracht = RekenTools.getSomProperty(BELASTBAAR_KEY, opdrachtElementen, new CheckRegime(taxdatum, BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY));
            herverdeelBedrijfsvoorheffing(luik.getVerminderingKey(), verminderingBvWerkbonusA, BELASTBAAR_KEY, bbOpdracht, opdrachtElementen);
        }

        return carryoverOut;
    }

    private boolean heeftWerkbonus(RekenContext context, RekenTijd rekenTijd) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> elementen = manager.getPersoonsElementen();
        return heeftWerkbonus(elementen, rekenTijd);
    }

    private boolean heeftWerkbonus(Collection<LoonElement> elementen, RekenTijd rekenTijd) {
        Money werkbonus = elementen.stream().map(x -> x.getPropertyMoney(WERKBONUS_LAGE_LONEN_KEY)).reduce(Money.ZERO, Money::add);
        if (rekenTijd.eindDatum.isBefore(GRENS_VERMINDERNG_BV_WERKBONONUS_ZONDER_HERSRTRUCT)) {
            Money werkbonusHerstructering = elementen.stream().map(x -> x.getPropertyMoney(VERMINDERING_HERSTRUCTERING_KEY)).reduce(Money.ZERO, Money::add);
            werkbonus = werkbonus.add(werkbonusHerstructering);
        }
        Money werkbonusB = elementen.stream().map(x -> x.getPropertyMoney(WERKBONUS_HEEL_LAGE_LONEN_KEY)).reduce(Money.ZERO, Money::add);
        return werkbonus.signum() != 0 || werkbonusB.signum() != 0;
    }

    protected void herverdeelBedrijfsvoorheffingOud(
            RekenContext context, Opdracht opdracht, VerminderinBvWerkbonus verminderingBvWerkbonus) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> opdrachtElementen = manager.getOpdrachtsElementen(opdracht);
        Money bbOpdracht = RekenTools.getSomProperty(BELASTBAAR_KEY, opdrachtElementen, new CheckRegime(taxdatum, BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY));
        herverdeelBedrijfsvoorheffing(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY, verminderingBvWerkbonus.getLuikA(), BELASTBAAR_KEY, bbOpdracht,
                opdrachtElementen);
        herverdeelBedrijfsvoorheffing(VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY, verminderingBvWerkbonus.getLuikB(), BELASTBAAR_KEY, bbOpdracht,
                opdrachtElementen);
    }

    protected void herverdeelBedrijfsvoorheffing(
            MoneyKey bvKey, Money bedrijfsvoorheffing, MoneyKey bbKey, Money totaalBelastbaar, Collection<LoonElement> loonElementen) {
        LoonElementChecker checkRegime = new CheckRegime(taxdatum, bvKey);
        BedragVerdelerFactory.verdeelBedragVolgensBasisPut(bvKey, bedrijfsvoorheffing, bbKey, totaalBelastbaar, loonElementen, checkRegime);
    }


}
